# hash_chaining.py
import hashlib
import json

class HashChainedLog:
    def __init__(self):
        self.previous_hash = None
        self.logs = []

    def append(self, entry: dict):
        # Hash the entry + previous hash
        entry_json = json.dumps(entry)
        current_hash = hashlib.sha256(
            (entry_json + self.previous_hash).encode()
        ).hexdigest()

        log_entry = {
            "entry": entry,
            "hash": current_hash,
            "previous_hash": self.previous_hash
        }

        self.logs.append(log_entry)
        self.previous_hash = current_hash

    def verify_integrity(self):
        # Verify all hashes in the chain
        previous_hash = None
        for log in self.logs:
            expected_hash = hashlib.sha256(
                (json.dumps(log["entry"]) + previous_hash).encode()
            ).hexdigest()

            if log["hash"] != expected_hash:
                return False

            previous_hash = log["hash"]

        return True
